    15→export function apiError(error: unknown): NextResponse {
    16→  if (error instanceof AuthError) {
    17→    return NextResponse.json({ error: error.message }, { status: error.status });
    18→  }
    19→  console.error("[API Error]", error);
    20→  return NextResponse.json({ error: "Internal server error" }, { status: 500 });
    21→}
