     4→async function aiServiceFetch<T>(
     5→  path: string,
     6→  body: unknown
     7→): Promise<T> {
     8→  const response = await fetch(`${AI_SERVICE_URL}${path}`, {
     9→    method: "POST",
    10→    headers: {
    11→      "Content-Type": "application/json",
    12→      "X-Service-Key": AI_SERVICE_SECRET_KEY,
    13→    },
    14→    body: JSON.stringify(body),
    15→  });
    16→
    17→  if (!response.ok) {
    18→    const text = await response.text();
    19→    throw new Error(`AI service error ${response.status}: ${text}`);
    20→  }
    21→
    22→  return response.json() as Promise<T>;
    23→}
