    23→      where: {
    24→        ...(query.type ? { type: query.type } : {}),
    25→        OR: [
    26→          { label: { contains: query.q, mode: "insensitive" } },
    27→          { description: { contains: query.q, mode: "insensitive" } },
    28→        ],
    29→      },
    30→      select: {
    31→        id: true,
    32→        type: true,
    33→        label: true,
    34→        description: true,
    35→        metadata: true,
    36→        parentId: true,
    37→      },
    38→      take: 20,
    39→      orderBy: { label: "asc" },
    40→    });
    41→
    42→    return NextResponse.json(nodes);
