     1→import { NextResponse } from "next/server";
     2→import { verifySignatureAppRouter } from "@upstash/qstash/nextjs";
     3→import { prisma } from "@compass/db";
     4→import { aiService } from "@/lib/ai-service";
     5→import { redis, CACHE_KEYS } from "@/lib/redis";
     6→import { getISOWeekKey } from "@/lib/utils";
     7→import { Client } from "@upstash/qstash";
     8→
     9→export const dynamic = "force-dynamic";
    10→export const maxDuration = 60;
    11→
    12→function getQStash() {
    13→  return new Client({ token: process.env.QSTASH_TOKEN! });
    14→}
    15→
    16→interface QStashPayload {
    17→  type: "WEEKLY_NUDGE_SWEEP" | "OPPORTUNITY_SWEEP" | "POST_SESSION_SYNTHESIS" | "EMBED_PROFILE";
    18→  data: Record<string, unknown>;
    19→  triggeredAt: string;
    20→}
    21→
    22→
    23→async function handler(req: Request) {
    24→  const body = (await req.json()) as QStashPayload;
    25→
    26→  switch (body.type) {
    27→    case "POST_SESSION_SYNTHESIS": {
    28→      const { studentId, sessionId } = body.data as {
    29→        studentId: string;
    30→        sessionId: string;
    31→      };
    32→      await handlePostSessionSynthesis(studentId, sessionId);
    33→      break;
    34→    }
    35→
    36→    case "WEEKLY_NUDGE_SWEEP": {
    37→      await handleWeeklyNudgeSweep();
    38→      break;
    39→    }
    40→
    41→    case "OPPORTUNITY_SWEEP": {
    42→      await handleOpportunitySweep();
    43→      break;
    44→    }
    45→
    46→    case "EMBED_PROFILE": {
    47→      const { studentId, summary } = body.data as {
    48→        studentId: string;
    49→        summary: string;
    50→      };
    51→      await handleEmbedProfile(studentId, summary);
    52→      break;
    53→    }
    54→
    55→    default:
    56→      return NextResponse.json(
    57→        { error: "Unknown job type" },
    58→        { status: 400 }
    59→      );
    60→  }
    61→
    62→  return NextResponse.json({ success: true });
    63→}
    64→
    65→async function handlePostSessionSynthesis(
    66→  studentId: string,
    67→  sessionId: string
    68→) {
    69→  // Fetch all relevant data
    70→  const [activities, reflections, previousProfile] = await Promise.all([
    71→    prisma.activity.findMany({
    72→      where: { studentId },
    73→      orderBy: { createdAt: "asc" },
    74→    }),
    75→    prisma.reflection.findMany({
    76→      where: { studentId },
    77→      orderBy: { createdAt: "asc" },
    78→    }),
    79→    prisma.signalProfile.findFirst({
    80→      where: { studentId, sessionId: { not: sessionId } },
    81→      orderBy: { createdAt: "desc" },
    82→    }),
    83→  ]);
    84→
    85→  const synthesis = await aiService.synthesizeProfile({
    86→    studentId,
    87→    sessionId,
    88→    activities,
    89→    reflections,
    90→    previousProfile,
    91→  });
    92→
    93→  // Save new signal profile (upsert for idempotency — QStash has at-least-once delivery)
    94→  await prisma.signalProfile.upsert({
    95→    where: { studentId_sessionId: { studentId, sessionId } },
    96→    create: {
    97→      studentId,
    98→      sessionId,
    99→      interestClusters: synthesis.interestClusters as object[],
   100→      characterSignals: synthesis.characterSignals as object[],
   101→      trajectoryShifts: synthesis.trajectoryShifts as object[],
   102→      gapDetection: synthesis.gapDetection as object,
   103→      breadthScore: synthesis.breadthScore,
   104→      compressedSummary: synthesis.compressedSummary,
   105→      lastSynthesizedAt: new Date(),
   106→    },
   107→    update: {
   108→      interestClusters: synthesis.interestClusters as object[],
   109→      characterSignals: synthesis.characterSignals as object[],
   110→      trajectoryShifts: synthesis.trajectoryShifts as object[],
   111→      gapDetection: synthesis.gapDetection as object,
   112→      breadthScore: synthesis.breadthScore,
   113→      compressedSummary: synthesis.compressedSummary,
   114→      lastSynthesizedAt: new Date(),
   115→    },
   116→  });
   117→
   118→  // Invalidate caches
   119→  await Promise.all([
   120→    redis.del(CACHE_KEYS.signalProfile(studentId)),
   121→    redis.del(CACHE_KEYS.personalizedMap(studentId)),
   122→  ]);
   123→
   124→  // Enqueue embedding update if AI service is available
   125→  try {
   126→    const aiServiceUrl = process.env.AI_SERVICE_URL;
   127→    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
   128→    if (aiServiceUrl) {
   129→      await getQStash().publishJSON({
   130→        url: `${appUrl}/api/webhooks/qstash`,
   131→        body: {
   132→          type: "EMBED_PROFILE",
   133→          data: { studentId, summary: synthesis.compressedSummary },
   134→          triggeredAt: new Date().toISOString(),
   135→        },
   136→        delay: 5,
   137→      });
   138→    }
   139→  } catch {
   140→    // Non-critical: embedding is for personalized map, not core feature
   141→  }
   142→}
