   315→async function handleEmbedProfile(studentId: string, summary: string) {
   316→  const aiServiceUrl = process.env.AI_SERVICE_URL;
   317→  if (!aiServiceUrl) return;
   318→
   319→  const res = await fetch(`${aiServiceUrl}/embed`, {
   320→    method: "POST",
   321→    headers: {
   322→      "Content-Type": "application/json",
   323→      "X-Service-Key": process.env.AI_SERVICE_SECRET_KEY ?? "",
   324→    },
   325→    body: JSON.stringify({ text: summary }),
   326→  });
   327→
   328→  if (!res.ok) {
   329→    throw new Error(`AI embed service returned ${res.status}`);
   330→  }
   331→
   332→  const embeddingData = (await res.json()) as { embedding: unknown };
   333→  const rawEmbedding = embeddingData.embedding;
   334→
   335→  if (
   336→    !Array.isArray(rawEmbedding) ||
   337→    rawEmbedding.length !== 1024 ||
   338→    !rawEmbedding.every((v): v is number => typeof v === "number" && isFinite(v))
   339→  ) {
   340→    throw new Error("Invalid embedding from AI service");
   341→  }
   342→
   343→  await redis.set(
   344→    `student-embedding:${studentId}`,
   345→    JSON.stringify(rawEmbedding),
   346→    { ex: 60 * 60 * 24 * 7 }
   347→  );
   348→}
