     9→function createPrismaClient() {
    10→  // Use DATABASE_URL (pgbouncer pooled) for runtime queries in serverless.
    11→  // DIRECT_URL is only for migrations (prisma db push/migrate).
    12→  const url = process.env.DATABASE_URL ?? process.env.DIRECT_URL ?? "";
    13→  // Supabase uses a CA not in Node's default trust store.
    14→  // If DB_SSL_CA is set (base64-encoded PEM from Supabase dashboard → Settings → Database → Download cert),
    15→  // we verify the full chain. Otherwise we still require TLS but skip chain verification —
    16→  // the connection is encrypted; MITM risk on Supabase's managed infra is negligible.
    17→  const sslCa = process.env.DB_SSL_CA
    18→    ? Buffer.from(process.env.DB_SSL_CA, "base64").toString("utf-8")
    19→    : undefined;
    20→
    21→  const pool = new Pool({
    22→    connectionString: url,
    23→    max: 1,
    24→    min: 0,
    25→    idleTimeoutMillis: 5000,
    26→    connectionTimeoutMillis: 10000,
    27→    allowExitOnIdle: true,
    28→    ssl: sslCa ? { ca: sslCa, rejectUnauthorized: true } : { rejectUnauthorized: false },
    29→  });
    30→  const adapter = new PrismaPg(pool);
    31→  return new PrismaClient({ adapter });
    32→}
    33→
    34→export const prisma = globalForPrisma.prisma ?? createPrismaClient();
